import{_ as e,o as r,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const l="/images/cover_use.png",d="/images/inline_1.png",o="/images/inline_2.png",i="/images/inline_3.png",x=JSON.parse('{"title":"算电协同上升国家战略：投资者需要知道的七件事","description":"《关于促进人工智能与能源双向赋能的行动方案》深度解读 — 29项重点任务全链条拆解，PE/VC投资地图","frontmatter":{"title":"算电协同上升国家战略：投资者需要知道的七件事","description":"《关于促进人工智能与能源双向赋能的行动方案》深度解读 — 29项重点任务全链条拆解，PE/VC投资地图"},"headers":[],"relativePath":"算电协同/算电协同上升国家战略_投资者需要知道的七件事.md","filePath":"算电协同/算电协同上升国家战略_投资者需要知道的七件事.md","lastUpdated":1781978464000}'),s={name:"算电协同/算电协同上升国家战略_投资者需要知道的七件事.md"};function h(g,t,c,p,_,u){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="算电协同上升国家战略-投资者需要知道的七件事" tabindex="-1">算电协同上升国家战略：投资者需要知道的七件事 <a class="header-anchor" href="#算电协同上升国家战略-投资者需要知道的七件事" aria-label="Permalink to &quot;算电协同上升国家战略：投资者需要知道的七件事&quot;">​</a></h1><blockquote><p><strong>政策标的</strong>: 《关于促进人工智能与能源双向赋能的行动方案》（国能发科技〔2026〕34号） <strong>发布时间</strong>: 2026年5月8日 | <strong>联合发布</strong>: 发改委、能源局、工信部、数据局 <strong>公众号</strong>: [道雷说道]</p></blockquote><p><img src="'+l+'" alt="封面图"></p><hr><p>2026年3月政府工作报告首次写入&quot;算电协同&quot;。5月8日，四部门联合印发专门行动方案。</p><p>这是过去五年里AI基础设施领域最系统的一份顶层设计文件：29项重点任务，覆盖从发电到用电、从芯片到电网、从投资到退出的全链条。</p><hr><h2 id="第一件-指令性政策-不是鼓励性政策" tabindex="-1">第一件：指令性政策，不是鼓励性政策 <a class="header-anchor" href="#第一件-指令性政策-不是鼓励性政策" aria-label="Permalink to &quot;第一件：指令性政策，不是鼓励性政策&quot;">​</a></h2><p><strong>四部门联合</strong>: 发改委（投资审批）、能源局（电力系统）、工信部（算力/AI产业）、数据局（算力基础设施）。</p><p><strong>时间表</strong>:</p><ul><li>2027年：安全、绿色、经济的能源保障体系初步构建</li><li>2030年：AI算力设施清洁能源供给保障能力达到&quot;世界领先水平&quot;</li></ul><p><strong>金融工具</strong>: REITs、绿色债券、&quot;两重&quot;&quot;两新&quot;资金渠道</p><p>算电协同不是&quot;试试看&quot;，是&quot;必须做&quot;。</p><p><img src="'+d+'" alt="政策与产业对比图"></p><hr><h2 id="第二件-绿电直连从试点走向标配" tabindex="-1">第二件：绿电直连从试点走向标配 <a class="header-anchor" href="#第二件-绿电直连从试点走向标配" aria-label="Permalink to &quot;第二件：绿电直连从试点走向标配&quot;">​</a></h2><p>配套文件《关于有序推动多用户绿电直连发展有关事项的通知》（688号文）核心变化：</p><table tabindex="0"><thead><tr><th>维度</th><th>过去（单用户）</th><th>现在（多用户）</th></tr></thead><tbody><tr><td>适用范围</td><td>单用户直连</td><td>多用户共享直连</td></tr><tr><td>参与主体</td><td>单一企业</td><td>工业园区、零碳园区、增量配电网</td></tr><tr><td>优先级</td><td>无明确指向</td><td><strong>优先支持算力设施</strong></td></tr><tr><td>分布式光伏</td><td>未涉及</td><td>可通过集中汇流参与</td></tr></tbody></table><p><strong>关键约束</strong>:</p><ul><li>自发自用电量 ≥ 可用发电量 <strong>60%</strong></li><li>自发自用电量 ≥ 总用电量 <strong>30%</strong>（2030年前≥35%）</li></ul><p><strong>测算</strong>: 2030年数据中心用电7000亿kWh，80%绿电直连、60%直连比例下，年节省输配电费约<strong>168亿元</strong>。</p><hr><h2 id="第三件-储能从可选变刚需" tabindex="-1">第三件：储能从可选变刚需 <a class="header-anchor" href="#第三件-储能从可选变刚需" aria-label="Permalink to &quot;第三件：储能从可选变刚需&quot;">​</a></h2><blockquote><p>&quot;鼓励算力设施配置构网型储能，增强供电稳定性。&quot;</p></blockquote><p>储能打开第四大应用场景——算力中心配储。数十GWh级别的增量市场。构网型储能、长时储能的技术溢价最高。</p><hr><h2 id="第四件-商业验证已完成" tabindex="-1">第四件：商业验证已完成 <a class="header-anchor" href="#第四件-商业验证已完成" aria-label="Permalink to &quot;第四件：商业验证已完成&quot;">​</a></h2><p>5月14日，全国首笔大型数据中心以虚拟电厂形式参与电力现货市场交易在广东落地。</p><ul><li>数据中心根据电价信号调整算力负载</li><li>参与方：粤能投平台 + 韶关数据中心集群</li><li>结果：用电成本降低<strong>10%-25%</strong>，商业模式跑通</li></ul><p>预计3-5年内超过1000个大型数据中心接入虚拟电厂，市场规模突破1000亿元。</p><hr><h2 id="第五件-首个大规模示范项目已并网" tabindex="-1">第五件：首个大规模示范项目已并网 <a class="header-anchor" href="#第五件-首个大规模示范项目已并网" aria-label="Permalink to &quot;第五件：首个大规模示范项目已并网&quot;">​</a></h2><p>5月2日，大唐集团宁夏中卫项目投运——全国首个大规模算电协同绿电直供项目。</p><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">数值</th></tr></thead><tbody><tr><td>光伏装机</td><td style="text-align:center;">50万千瓦</td></tr><tr><td>风电（在建）</td><td style="text-align:center;">150万千瓦</td></tr><tr><td>年发电量</td><td style="text-align:center;">22.9亿kWh</td></tr><tr><td>模式</td><td style="text-align:center;">物理直供 + 双边交易双轨并行</td></tr></tbody></table><p>2025年7月到2026年5月，乌兰察布、克拉玛依、庆阳、中卫项目密集落地，累计装机逼近千万千瓦。</p><p><img src="'+o+'" alt="宁夏中卫算电协同示范项目"></p><hr><h2 id="第六件-ai用电增速远超预期" tabindex="-1">第六件：AI用电增速远超预期 <a class="header-anchor" href="#第六件-ai用电增速远超预期" aria-label="Permalink to &quot;第六件：AI用电增速远超预期&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">时间</th><th style="text-align:center;">全国数据中心用电量</th><th style="text-align:center;">同比增速</th></tr></thead><tbody><tr><td style="text-align:center;">2025全年</td><td style="text-align:center;">1,933亿kWh</td><td style="text-align:center;">+17.0%</td></tr><tr><td style="text-align:center;">2026年1-2月</td><td style="text-align:center;">—</td><td style="text-align:center;"><strong>+46.2%</strong></td></tr></tbody></table><p>数据中心用电增速是全社会用电增速的10倍。到2030年预计达7,000-8,000亿kWh，占全社会用电5%以上。</p><hr><h2 id="第七件-投资地图" tabindex="-1">第七件：投资地图 <a class="header-anchor" href="#第七件-投资地图" aria-label="Permalink to &quot;第七件：投资地图&quot;">​</a></h2><p><img src="'+i+'" alt="算电协同投资地图"></p><h3 id="三条主线" tabindex="-1">三条主线 <a class="header-anchor" href="#三条主线" aria-label="Permalink to &quot;三条主线&quot;">​</a></h3><ol><li><strong>电力设备</strong>（确定性最高）：特高压变压器、绿电直连专线设备、构网型储能、800V HVDC</li><li><strong>新能源运营</strong>（弹性最大）：西部风光电站算力长协、算电协同项目开发</li><li><strong>AI调度平台</strong>（估值想象最大）：虚拟电厂运营商、算力-电力协同调度软件</li></ol><h3 id="关键时点" tabindex="-1">关键时点 <a class="header-anchor" href="#关键时点" aria-label="Permalink to &quot;关键时点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">时点</th><th>事件</th><th style="text-align:center;">影响</th></tr></thead><tbody><tr><td style="text-align:center;">2026 Q3</td><td>各省实施细则出台</td><td style="text-align:center;">地方政策竞赛开启</td></tr><tr><td style="text-align:center;">2026 Q3-Q4</td><td>首批国家级试点申报</td><td style="text-align:center;">赛道正式开通</td></tr><tr><td style="text-align:center;">2027</td><td>算电协同REITs首单</td><td style="text-align:center;">退出通道打开</td></tr><tr><td style="text-align:center;">2030</td><td>政策目标节点</td><td style="text-align:center;">行业格局基本定型</td></tr></tbody></table><hr><p>如果觉得有收获——点赞·在看·评论·收藏。</p><p>📌 <strong>投资同行</strong> → 关注公众号「道雷说道」，每周拆解一个能源×AI赛道</p><p><em>免责声明：本文仅为投资研究视角分享，不构成任何投资建议。政策解读基于公开文件。</em></p>',51)])])}const q=e(s,[["render",h]]);export{x as __pageData,q as default};
